package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n", "\\N", null, null, false, false, false, false, false);
    }

    @Test
    public void testGetCommentMarker() {
        // Given
        Character expected = '#';
        assertEquals(expected, csvFormat.getCommentMarker());
    }

    @Test
    public void testGetCommentMarkerWhenNull() {
        // Given
        csvFormat = new CSVFormat(',', '"', null, null, '\\', true, false, "\r\n", "\\N", null, null, false, false, false, false, false);
        Character expected = null;
        assertEquals(expected, csvFormat.getCommentMarker());
    }

    @Test
    public void testIsCommentMarkerSet() {
        // Given
        assertTrue(csvFormat.isCommentMarkerSet());
    }

    private void assertTrue(boolean commentMarkerSet) {
        // Use reflection to access private method isCommentMarkerSet
        try {
            CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n", "\\N", null, null, false, false, false, false, false);
            java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod("isCommentMarkerSet");
            method.setAccessible(true);
            boolean result = (boolean) method.invoke(csvFormat);
            assertEquals(commentMarkerSet, result);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
